SELECT report_id, COUNT(DISTINCT user_id) AS num_unique_users
FROM report_access
GROUP BY report_id;

SELECT COUNT(*) 
FROM data_integrity_logs
WHERE status = 'failed';

SELECT *
FROM data_integrity_logs
WHERE status = 'failed';

SELECT wd.measurement_id, wd.station_id, dil.check_date
FROM wave_data wd
JOIN data_integrity_logs dil ON wd.measurement_id = dil.measurement_id;

SELECT station_id, AVG(water_temperature) AS avg_temp
FROM wave_data
GROUP BY station_id;

SELECT u.*, a.*
FROM users u
LEFT JOIN access_logs a ON u.user_id = a.user_id;

SELECT wd.*, dil.check_date, dil.status, dil.methodology, dil.results, dil.action_taken
FROM wave_data wd
INNER JOIN data_integrity_logs dil ON wd.measurement_id = dil.measurement_id;
